&LogGUID = GUID.NewGuid()
//verifica id da sessao.
verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)

if &IsAcessoConcedido = true //Acesso concedido	

	RetornaConfSistema_wpPessoa.Call(&wwpContext.EmpCod, &wwpContext.FilCod, &sdtConfig_wpPessoa)

//	&AuxLongVarchar = &Cadastro
//	&AuxLongVarchar = &AuxLongVarchar.Replace('"Emails":"[{', '"Emails":[{')
//	&AuxLongVarchar = &AuxLongVarchar.Replace('"Fones":"[{', '"Fones":[{')
//	&AuxLongVarchar = &AuxLongVarchar.Replace('}]"', '}]')

//	&sdtCliente.FromJson(&AuxLongVarchar)

//	padraousuario.Call('G', 'set_cliente', 1, 1, &AuxLongVarchar, &PadDtaMod)
//	padraousuario.Call('G', 'set_cliente1', 1, 1, &sdtCliente.ToJson(), &PadDtaMod)

	//CARREGA DADOS ATUAIS
	if &sdtCliente.Cod <> 0 //carrega dados do cadastro
		&OqueFazer = 'UPD'
		prcLoadPessoa.Call(&wwpContext.EmpCod, &sdtCliente.Cod, &SdtwpPessoa)

		For Each Order EmpCod, PesCod
			Where EmpCod = &wwpContext.EmpCod
			Where PesCod = &sdtCliente.Cod

			//EMAIL
			For Each Order EmpCod PesCod, PesEmlCod
				&sdtGravaPessoaEmail = new()
				&sdtGravaPessoaEmail.PesEmls = PesEml
				&sdtGravaPessoaEmail.PesEmlCod = PesEmlCod
				&sdtGravaPessoaEmail.PesEmlCon = PesEmlCon
				&sdtGravaPessoaEmail.PesEmlCht = PesEmlCht
				&sdtGravaPessoaEmail.PesEmlFin = PesEmlFin
				&sdtGravaPessoaEmail.PesEmlPed = PesEmlPed
				&sdtGravaPessoaEmail.PesEmlFat = PesEmlFat
				&sdtGravaPessoaEmail.PesEmlDtaNas = PesEmlDtaNas
				&sdtGravaPessoaEmail.PesEmlSts = Status_SimNao.Sim
				&sdtGravaPessoa2.Email.Add(&sdtGravaPessoaEmail)
				&CountEmail = PesEmlCod
			EndFor

			//FONE
			For each order EmpCod PesCod, PesFonCod
				&sdtGravaPessoaFone = new()
				&sdtGravaPessoaFone.PesFonCod = PesFonCod
				&sdtGravaPessoaFone.PesFonNums = PesFonNum
				&sdtGravaPessoaFone.PesFonTpo = PesFonTpo
				&sdtGravaPessoaFone.PesFonOpe = PesFonOpe
				&sdtGravaPessoaFone.PesFonConTip.FromString(PesFonConTip)
				&sdtGravaPessoaFone.PesFonCon = PesFonCon
				&sdtGravaPessoaFone.PesFonDtaNas = PesFonDtaNas
				&sdtGravaPessoaFone.PesFonSts = Status_SimNao.Sim
				&sdtGravaPessoaFone.PesFOnWhatsBol = PesFonWhatsBol

				&sdtGravaPessoaFone.PesFonWhatsPed = PesFonWhatsPed
				&sdtGravaPessoaFone.PesFonWhatsFat = PesFonWhatsFat 

				&sdtGravaPessoa.Fone.Add(&sdtGravaPessoaFone)			
				&CountFone = PesFonCod
			EndFor
		EndFor		

		if &SdtwpPessoa.PesCod = 0
			&Mensagem = 'Código invalido.'
			do 'msgErro'
			return
		Endif

	Else //CArregar dados padroes
		&OqueFazer = 'INS'

		&SdtwpPessoa.EmpCod = &wwpContext.EmpCod //Empresa
		&SdtwpPessoa.PesProAtv = 'N'
		&SdtwpPessoa.PesExtVenCod = 1
		&SdtwpPessoa.OriCod = OrigemCadastroPessoa.SMARTPHONE			
		&SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO			 
		&SdtwpPessoa.PesDscMax = 100
		&SdtwpPessoa.PesCliHabVenInt = true		

		retornaConfSistema.Call(&wwpContext.EmpCod, &wwpContext.FilCod, domConfSistema.TCon203_PadraoVendaPrazoAPP, &TCon203_PadraoVendaPrazoAPP)
		&SdtwpPessoa.PesVenAprz = iif(&TCon203_PadraoVendaPrazoAPP = 'S', Status_SimNao.Nao, Status_SimNao.Sim)

	Endif

	&SdtwpPessoa.PesSts = &sdtCliente.Sts
	&SdtwpPessoa.PesRaz = &sdtCliente.Raz.ToUpper()
	&SdtwpPessoa.PesFan = &sdtCliente.Fan.ToUpper()

	&SdtwpPessoa.PesTip = &sdtCliente.Tip
	&SdtwpPessoa.PesCpf = &sdtCliente.Cpf
	&SdtwpPessoa.PesCnpj = &sdtCliente.Cnpj
	&SdtwpPessoa.PesInsEst = &sdtCliente.InsEst

	&SdtwpPessoa.PesCep = &sdtCliente.Cep
	&SdtwpPessoa.PesLog = &sdtCliente.Log.ToUpper()
	&SdtwpPessoa.PesNro = &sdtCliente.Nro.ToUpper()
	&SdtwpPessoa.PesBai = &sdtCliente.Bai.ToUpper()

	&SdtwpPessoa.PesCpl = &sdtCliente.Cpl.ToUpper()
	&SdtwpPessoa.PesRef = &sdtCliente.Ref.ToUpper()

	&SdtwpPessoa.PesGruImpCod = &sdtCliente.ImpCod

	&SdtwpPessoa.PEsCidCod = &sdtCliente.CidC
	&CidCod = &sdtCliente.CidC 
	//GET CIDADE
	do 'getCidade'

	&SdtwpPessoa.PesIsCli = iif(&sdtCliente.IsCli = 1, true, false)
	&SdtwpPessoa.PesIsFor = iif(&sdtCliente.IsFor = 1, true, false)
	&SdtwpPessoa.PesIsTra = iif(&sdtCliente.isTra = 1, true, false)
	&SdtwpPessoa.PesIsMot = iif(&sdtCliente.isMot = 1, true, false)

    &SdtwpPessoa.PesObsNfe = &sdtCliente.ObsNfe
	&SdtwpPessoa.PesRazNF = &sdtCliente.RazNf

	//Emails
	For &sdtEmailsItem in &sdtCliente.Emails
		Do Case
			Case &sdtEmailsItem.Cod = 0 and &sdtEmailsItem.Sts <> 'S'
				//IGNORA

			Case &sdtEmailsItem.Cod = 0 and &sdtEmailsItem.Sts = 'S'
				//ADD
				&CountEmail += 1
				&sdtGravaPessoaEmail = new()
				&sdtGravaPessoaEmail.PesEmls = &sdtEmailsItem.Eml
				&sdtGravaPessoaEmail.PesEmlCod = &CountEmail
				&sdtGravaPessoaEmail.PesEmlCon = &sdtEmailsItem.Con
				//&sdtGravaPessoaEmail.PesEmlCht = ''
				&sdtGravaPessoaEmail.PesEmlFin = iif(&sdtEmailsItem.Fin = 1, true, false)
				&sdtGravaPessoaEmail.PesEmlPed = iif(&sdtEmailsItem.Ped = 1, true, false)
				&sdtGravaPessoaEmail.PesEmlFat = iif(&sdtEmailsItem.Fat = 1, true, false)
				//&sdtGravaPessoaEmail.PesEmlDtaNas.iif(&sdtEmailsItem.Ped = 1, true, false)
				&sdtGravaPessoaEmail.PesEmlSts = Status_SimNao.Sim
				&sdtGravaPessoa2.Email.Add(&sdtGravaPessoaEmail)

			Case &sdtEmailsItem.Cod <> 0 and &sdtEmailsItem.Sts <> 'S'
				//DEL
				For &sdtGravaPessoaEmail in &sdtGravaPessoa2.Email
					If &sdtGravaPessoaEmail.PesEmlCod = &sdtEmailsItem.Cod
						&sdtGravaPessoaEmail.PesEmlSts = Status_SimNao.Nao
						Exit
					EndIf
				EndFor	

			Case &sdtEmailsItem.Cod <> 0 and &sdtEmailsItem.Sts = 'S'
				//UPDATE
				For &sdtGravaPessoaEmail in &sdtGravaPessoa2.Email
					If &sdtGravaPessoaEmail.PesEmlCod = &sdtEmailsItem.Cod
						&sdtGravaPessoaEmail.PesEmlCon = &sdtEmailsItem.Con
						&sdtGravaPessoaEmail.PesEmls = &sdtEmailsItem.Eml
						&sdtGravaPessoaEmail.PesEmlFat = iif(&sdtEmailsItem.Fat = 1, true, false)
						&sdtGravaPessoaEmail.PesEmlFin = iif(&sdtEmailsItem.Fin = 1, true, false)
						&sdtGravaPessoaEmail.PesEmlPed = iif(&sdtEmailsItem.Ped = 1, true, false)
						Exit
					EndIf
				EndFor	
		EndCase
	EndFor	

	//Fones
	For &sdtFonesItem in &sdtCliente.Fones
		Do Case
			Case &sdtFonesItem.Cod = 0 and &sdtFonesItem.Sts <> 'S'
				//IGNORA

			Case &sdtFonesItem.Cod = 0 and &sdtFonesItem.Sts = 'S'
				//ADD
				&CountFone += 1
				&sdtGravaPessoaFone = new()
				&sdtGravaPessoaFone.PesFonCod = &CountFone
				&sdtGravaPessoaFone.PesFonNums = &sdtFonesItem.Num
				//&sdtGravaPessoaFone.PesFonTpo = PesFonTpo
				&sdtGravaPessoaFone.PesFonOpe.FromString(&sdtFonesItem.Ope)
				&sdtGravaPessoaFone.PesFonConTip.FromString(&sdtFonesItem.Tip)
				&sdtGravaPessoaFone.PesFonCon = &sdtFonesItem.con
				//&sdtGravaPessoaFone.PesFonDtaNas = PesFonDtaNas
				&sdtGravaPessoaFone.PesFonSts = Status_SimNao.Sim

				&sdtGravaPessoaFone.PesFOnWhatsBol = iif(&sdtFonesItem.Fin = 1, true, false) 
				&sdtGravaPessoaFone.PesFonWhatsPed = iif(&sdtFonesItem.Ped = 1, true, false) 
				&sdtGravaPessoaFone.PesFonWhatsFat = iif(&sdtFonesItem.Fat = 1, true, false) 

				&sdtGravaPessoa.Fone.Add(&sdtGravaPessoaFone)			

			Case &sdtFonesItem.Cod <> 0 and &sdtFonesItem.Sts <> 'S'
				//DEL
				For &sdtGravaPessoaFone in &sdtGravaPessoa.Fone
					If &sdtGravaPessoaFone.PesFonCod = &sdtFonesItem.Cod
						&sdtGravaPessoaFone.PesFonSts = Status_SimNao.Nao
						Exit
					EndIf
				EndFor

			Case &sdtFonesItem.Cod <> 0 and &sdtFonesItem.Sts = 'S'
				//UPDATE
				For &sdtGravaPessoaFone in &sdtGravaPessoa.Fone
					If &sdtGravaPessoaFone.PesFonCod = &sdtFonesItem.Cod
						&sdtGravaPessoaFone.PesFonNums = &sdtFonesItem.Num
						//&sdtGravaPessoaFone.PesFonTpo = PesFonTpo
						&sdtGravaPessoaFone.PesFonOpe.FromString(&sdtFonesItem.Ope)
						&sdtGravaPessoaFone.PesFonConTip.FromString(&sdtFonesItem.Tip)
						&sdtGravaPessoaFone.PesFonCon = &sdtFonesItem.con
						&sdtGravaPessoaFone.PesFonWhatsFat = iif(&sdtFonesItem.Fat = 1, true, false)
						&sdtGravaPessoaFone.PesFOnWhatsBol = iif(&sdtFonesItem.Fin = 1, true, false)
						&sdtGravaPessoaFone.PesFonWhatsPed = iif(&sdtFonesItem.Ped = 1, true, false)
						Exit
					EndIf
				EndFor
		EndCase
	EndFor	

	do 'validaCNPJvalidaCPF'	
	do 'VerificaFone'
	do 'VerificaEmail'

	&InsSimNao.SetEmpty()
	prcValidaInscricaoEstadual.Call(&PesInsEst, &PesCidUfeCod, &InsSimNao, &PesInsEst) 

	Do Case	
		Case &SdtwpPessoa.PesTip.IsEmpty()
			&Mensagem = 'Tipo Pessoa não selecionado.'
			do 'msgErro'

		Case &SdtwpPessoa.PesRaz.IsEmpty()
			&Mensagem = 'Razão Social é obrigatório.'
			do 'msgErro'

			//JDF - SMART NAO VAI INFORMAR CODIGO
			//		case &IsDisponivel = false and not &PesCod.IsEmpty() and &OqueFazer = 'INS'
			//			&Mensagem = 'Código já utilizado, Informe outro Código para o Cadastro.'
			//			do 'msgErro'

		Case (&Cnpj_Erro = 1) and &SdtwpPessoa.PesTip = TipoPessoa.JURIDICA and &PesCidUfeCod <> 'EX' //and &OqueFazer <> 'DEL' 
			&Mensagem = 'ERRO! CNPJ informado Inválido!'	
			do 'msgErro'

		Case &Cpf_Erro = 1 and &SdtwpPessoa.PesTip = TipoPessoa.FISICA  and &PesCidUfeCod <> 'EX' //and &OqueFazer <> 'DEL'
			&Mensagem = 'ERRO! CPF informado Inválido!'  
			do 'msgErro'

		Case &IsCnpjCpfErroRepetido = true and (&sdtConfig_wpPessoa.TCon004_BloquearCpfCnpjRepetido = 'N')  and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO and &SdtwpPessoa.PesIsCli = true 
			&Mensagem = 'ERRO! Não é permitido o cadastro de clientes com CPF/CNPJ repetido! ' + &ClienteCpfCnpjRepetidoMensagem
			do 'msgErro'

		Case &InsSimNao = 'N' and not &PesInsEst.IsEmpty() and &SdtwpPessoa.PesTip = TipoPessoa.JURIDICA  and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Inscrição Estadual Inválida!'
			do 'msgErro'

			//		Case (&PesIntVenCod > 1 and (&PesIntIsVen = false or &PesIntVenIntExt <> Status_internoExterno.INTERNO) and &PesIsCli = true) and (&OqueFazer = 'INS' or &sdtConfig_wpPessoa.WPALTERAVENDEDORCLIENTE_AutNiv > 0) //INS POR HORA. DEPOIS VAI FICAR HABILITADO, JDF
			//			GXUITabsPanel_TabsPessoa.SelectTab(3)	
			//			&Mensagem = 'Insira um Vendedor Interno válido!'
			//			do 'msgErro'
			//			&PesIntVenCodNom.SetFocus()

			//		Case (&PesExtVenCod > 1 and (&PesExtIsVen = false or &PesExtVenIntExt <> Status_internoExterno.EXTERNO) and &PesIsCli = true) and (&OqueFazer = 'INS' or &sdtConfig_wpPessoa.WPALTERAVENDEDORCLIENTE_AutNiv > 0) //INS POR HORA. DEPOIS VAI FICAR HABILITADO, JDF
			//			GXUITabsPanel_TabsPessoa.SelectTab(3)	
			//			&Mensagem = 'Insira um Vendedor Externo válido!'
			//			do 'msgErro'
			//			&PesExtVenCodNom.SetFocus()

		CAse (&sdtConfig_wpPessoa.TCon006_ObrigatorioEndereco = 'S') AND &SdtwpPessoa.PesCep.IsEmpty() and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'CEP é obrigatório.'
			do 'msgErro'

		CAse (&sdtConfig_wpPessoa.TCon006_ObrigatorioEndereco = 'S') AND (&SdtwpPessoa.PesLog.IsEmpty() or &SdtwpPessoa.PesLog.Length() < 5) and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Logradouro é obrigatório e deve ter mais de 4 digitos.'
			do 'msgErro'

		CAse (&sdtConfig_wpPessoa.TCon006_ObrigatorioEndereco = 'S') AND &SdtwpPessoa.PesNro.IsEmpty() and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Número do endereço é obrigatório.'
			do 'msgErro'

		Case  (&sdtConfig_wpPessoa.TCon006_ObrigatorioEndereco = 'S') AND (&SdtwpPessoa.PesBai.IsEmpty() or &SdtwpPessoa.PesBai.Length() < 5) and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Bairro é obrigatório e deve ter mais de 4 digitos.'
			do 'msgErro'

		CAse (&sdtConfig_wpPessoa.TCon006_ObrigatorioEndereco = 'S') AND (&SdtwpPessoa.PesCidCod.IsEmpty() or &PesCidNom.IsEmpty())  and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Cidade é obrigatório.'
			do 'msgErro'

			//		CAse (&PesEstCiv in (2,3)) AND &PesNomCon.IsEmpty() and &PesSts = Status_AtivoInativo.ATIVO
			//			GXUITabsPanel_TabsPessoa.SelectTab(2)
			//			&Mensagem = 'Nome Conjuge é obrigatório para Estado civil, CASADO/AMASIADO.'
			//			do 'msgErro'
			//			&PesNomCon.SetFocus()
			//			
			//		CAse &PesSetCod.IsEmpty() and (&PesIsFun = true or &PesIsVen = true) and &PesSts = Status_AtivoInativo.ATIVO
			//			GXUITabsPanel_TabsPessoa.SelectTab(2)
			//			&Mensagem = 'Setor não Informado, informação Obrigatória.'
			//			do 'msgErro'
			//			&SetCodNom.SetFocus()
			//			
			//		CAse &FucCod.IsEmpty() and (&PesIsFun = true or &PesIsVen = true) and &PesSts = Status_AtivoInativo.ATIVO
			//			GXUITabsPanel_TabsPessoa.SelectTab(2)
			//			&Mensagem = 'Função não Informada, informação Obrigatória.'
			//			do 'msgErro'
			//			&FucCodNom.SetFocus()
			//			
			//		Case &PesCliTraIs = false and &PesCliTraCod > 1 and not &PesCliTraCodRaz.IsEmpty() and &PesSts = Status_AtivoInativo.ATIVO
			//			GXUITabsPanel_TabsPessoa.SelectTab(3)
			//			&Mensagem = 'Insira Uma Transportadora válida!'
			//			do 'msgErro'
			//			&PesCliTraCodRaz.SetFocus()
			//			
			//		Case &PesDiaCob > 31 and &OqueFazer <> 'DEL'
			//			GXUITabsPanel_TabsPessoa.SelectTab(4)
			//			&Mensagem = 'Valor Inválido, o valor Máximo Permitido é "31"!'
			//			do 'msgErro'
			//			&PesDiaCob.SetFocus()

		Case &IsErrorFone = true
			&Mensagem = &TotalFoneMensagem
			do 'msgErro'

		Case &IsErrorEmail = true
			&Mensagem = &TotalEmailMensagem
			do 'msgErro'

			//		Case not &PesEnd_RepetidoMensagem.IsEmpty() and &sdtConfig_wpPessoa.TCon116_EnderecoRepetido = 'S'
			//			GXUITabsPanel_TabsPessoa.SelectTab(1)
			//			&Mensagem = &PesEnd_RepetidoMensagem
			//			do 'msgErro'
			//			&PesLog.SetFocus()

			//Case Not &PesVinCod.IsEmpty() and &PesVinCod <> &PesCod
			//	&Mensagem = 'Pessoa Inexistente para o Vínculo!'
			//	do 'msgErro'			
			//	&PesVinCodRaz.SetFocus()

			//		Case not &PesVinCod.IsEmpty() And &IsErroVinculo = true 
			//			GXUITabsPanel_TabsPessoa.SelectTab(3)
			//			&Mensagem = 'ATENÇÃO! Cliente ' + trim(str(&PesVinCod)) + ' já vinculado em outros Clientes, portanto não pode ser vínculado com outro!'
			//			do 'msgErro'
			//			&PesVinCodRaz.SetFocus()
			//			
			//		CAse not &PesVinCod.IsEmpty() And &IsErroVinculoPrincipal = true 
			//			GXUITabsPanel_TabsPessoa.SelectTab(3)
			//			&Mensagem = 'ATENÇÃO! Cliente ' + trim(str(&PesCod)) + ' já vinculado em outros Clientes, portanto não pode ser vínculado com outro!'
			//			do 'msgErro'
			//			&PesVinCodRaz.SetFocus()
			//			
			//		Case &sdtConfig_wpPessoa.TCon134_ObrigatorioRegimeFiscal = 'S' and &PesSts = Status_AtivoInativo.ATIVO and &PesIsCli= true and &PesReg.IsEmpty() and &PesTip = TipoPessoa.JURIDICA
			//			GXUITabsPanel_TabsPessoa.SelectTab(2)
			//			&Mensagem = 'ATENÇÃO! Obrigatório informar o Tipo de Regime!'
			//			do 'msgErro'
			//			&PesReg.SetFocus()
			//			
			//		Case &sdtConfig_wpPessoa.TCon134_ObrigatorioRegimeFiscal = 'S' and &PesSts = Status_AtivoInativo.ATIVO and &PesIsCli= true and &PesPedProAlg.IsEmpty() and &PesTip = TipoPessoa.JURIDICA
			//			GXUITabsPanel_TabsPessoa.SelectTab(2)
			//			&Mensagem = 'ATENÇÃO! Obrigatório informar Tipo de Prédio!'
			//			do 'msgErro'
			//			&PesPedProAlg.SetFocus()
		Case &SdtwpPessoa.PesGruImpCod.IsEmpty() and &SdtwpPessoa.PesIsCli = true and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO
			&Mensagem = 'Grupo de imposto não selecionado'
			do 'msgErro'

		Otherwise			
			if &SdtwpPessoa.PesFan.IsEmpty()
				&SdtwpPessoa.PesFan = &SdtwpPessoa.PesRaz
			Endif
			////			
			////			if &SdtwpPessoa.PesIntVenCod <> &PesIntVenCod
			////				&OldPesIntVenCod = &SdtwpPessoa.PesIntVenCod 
			////				&IsAlterouVendedorInterno = true
			////			Endif

			////			if &sdtwpPessoa.PesExtVenCod <> &PesExtVenCod
			////				&OldPesExtVenCod = &sdtwpPessoa.PesExtVenCod
			////				&IsAlterouVendedorExterno = true
			////			Endif

			prcGravaPessoa.Call(&OqueFazer, &wwpContext.EmpCod, &wwpContext.FilCod, &SdtwpPessoa, &wwpContext.UserName, &outPesCod)
			GravaCliente_FoneEmail.Call(&wwpContext.EmpCod, &wwpContext.FilCod, &outPesCod, &sdtGravaPessoa, &sdtGravaPessoa2, &wwpContext.UserName)

			PessoaPrimeiroFoneEmail.Call(&wwpContext.EmpCod, &outPesCod, &PesPrmEml, &PesPrmFon)
			prcAtualizaAniversariantes.Call('ADD', &wwpContext.EmpCod, &SdtwpPessoa.PesRaz, TipoAniversario.Pessoa, Status_SimNao.Sim, 0, '', &SdtwpPessoa.PesDtaNas, &outPesCod, 0, &PesPrmfon, &PesPrmEml)


	//			if &IsAlterouContas = true
	//				GravaCliente_ContasBancarias.Call(&wwpContext.EmpCod, &outPesCod, &sdtContasBancarias)
	//			Endif
