Sub 'msgerro'
	&sdtRetornowbsetc.Sts = 'E900'
	&sdtRetornowbsetc.Obs = &Mensagem
	return
EndSub

Sub 'getCidade'

	&PesCidUfeCod.SetEmpty()
	&PesCidNom.SetEmpty()
	For Each Order EmpCod, CidCod
		Where EmpCod = &wwpContext.EmpCod
		Where CidCod = &CidCod
		&PesCidNom = CidNom
		&PesCidUfeCod = UfeCod
		Exit
	EndFor
EndSub


Sub 'validaCNPJValidaCPF'

	&Cnpj_Erro.SetEmpty()
	&Cpf_Erro.SetEmpty()
	&Mensagem.SetEmpty()
	IF (&SdtwpPessoa.PesTip = TipoPessoa.JURIDICA and &SdtwpPessoa.PesSts <> Status_AtivoInativo.ATIVO and &SdtwpPessoa.PesIsCli = false) and &PesCidUfeCod <> 'EX'
		ValidaCpfCnpj.Call(&SdtwpPessoa.PesCnpj, &Cnpj_Erro, &sdtConfig_wpPessoa.TCon001_CpfCnpjObrigatorio)
		if &SdtwpPessoa.PesCnpj.Length() < 18 and not &SdtwpPessoa.PesCnpj.IsEmpty()
			&Cnpj_Erro = 1
		Endif
	Else
		ValidaCpfCnpj.Call(&SdtwpPessoa.PesCnpj, &Cnpj_Erro, 'N')
		if &SdtwpPessoa.PesCnpj.Length() < 18 and not &SdtwpPessoa.PesCnpj.IsEmpty()
			&Cnpj_Erro = 1
		Endif
	Endif

	IF (&SdtwpPessoa.PesTip = TipoPessoa.FISICA and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO and &SdtwpPessoa.PesIsCli = true ) and &PesCidUfeCod  <> 'EX'
		ValidaCpfCnpj.Call(&SdtwpPessoa.PesCpf, &Cpf_Erro, &sdtConfig_wpPessoa.TCon001_CpfCnpjObrigatorio)
		if (&SdtwpPessoa.PesCpf.Length() > 14)
			&Cpf_Erro = 1
		Endif
	Else
		ValidaCpfCnpj.Call(&SdtwpPessoa.PesCpf, &Cpf_Erro, 'N')
	Endif
	do 'CPFCNPJ_Repetido'

EndSub

Sub 'CPFCNPJ_Repetido'

	if &sdtConfig_wpPessoa.TCon004_BloquearCpfCnpjRepetido = 'N' and &SdtwpPessoa.PesSts = Status_AtivoInativo.ATIVO 
		ValidaCpfCnpjRepetido.call(&wwpContext.EmpCod, &SdtwpPessoa.PesCod, &SdtwpPessoa.PesCnpj, &SdtwpPessoa.PesCpf, &SdtwpPessoa.PesTip, &IsCnpjCpfErroRepetido, &ClienteCpfCnpjRepetidoMensagem)
	Endif

EndSub

Sub 'ValidaFone'
	RetornaSoNumeros.Call(&FoneVerificacao, &AuxFone)
	if &AuxFone.Length() >= 10 and &AuxFone.Length() < 13
	else
		&TotalFoneMensagem += ' Número de telefone inválido. Verifique no item ' + trim(str(&PesFonCod)) + ' !'
		&IsErrorFone = true
	EndIf
EndSub

Sub 'VerificaFone'
	&IsErrorFone = false
	For &sdtGravaPessoaFone in &sdtGravaPessoa.Fone
		if &sdtGravaPessoaFone.PesFonSts = Status_SimNao.Sim

			FormataFone.Call(&sdtGravaPessoaFone.PesFonNums, &sdtGravaPessoaFone.PesFonNums)

			Do case
				case &sdtGravaPessoaFone.PesFonNums.IsEmpty() and (not &sdtGravaPessoaFone.PesFonCon.IsEmpty())
					&IsErrorFone = true
					&TotalFoneMensagem += ' Obrigatório preencher o Número de contato no item ' + trim(str(&sdtGravaPessoaFone.PesFonCod)) + ' !'

				case not &sdtGravaPessoaFone.PesFonNums.IsEmpty() 
					&PesFonCod = &sdtGravaPessoaFone.PesFonCod
					&FoneVerificacao = &sdtGravaPessoaFone.PesFonNums
					Do 'ValidaFone'
			EndCase			
		EndIf
	EndFor
EndSub


Sub 'ValidaEmail'
	&pattern = "^((\w+([-+.']\w+)*@\w+([-.]\w+)*\.\w+([-.]\w+)*)|(\s*))$" // valid email address pattern
	if (&EmailVerificacao.IsMatch(&pattern) = false)
		&TotalEmailMensagem += ' Endereço de E-mail não coincide com o padrão especificado no item ' + trim(str(&PesEmlCod)) + ' !'
		&IsErrorEmail = True
	EndIf
EndSub

Sub 'VerificaEmail'
	&IsErrorEmail = false
	&TotalEmailMensagem.SetEmpty()
	For &sdtGravaPessoaEmail in &sdtGravaPessoa2.Email
		if &sdtGravaPessoaEmail.PesEmlSts = Status_SimNao.Sim			
			if not &sdtGravaPessoaEmail.PesEmls.IsEmpty()
				&PesEmlCod = &sdtGravaPessoaEmail.PesEmlCod
				&EmailVerificacao = &sdtGravaPessoaEmail.PesEmls
				Do 'ValidaEmail'
			Else
				if not &sdtGravaPessoaEmail.PesEmlCon.IsEmpty() or not &sdtGravaPessoaEmail.PesEmlCht.IsEmpty()
					&IsErrorEmail = true
					&TotalEmailMensagem += ' Obrigatório preencher o e-mail no item ' + trim(str(&sdtGravaPessoaEmail.PesEmlCod)) + ' !'
				Endif
			Endif
		EndIf
	EndFor
EndSub

